/**
 * @summary Get user progress data
 */
export const getGetProgressUrl = () => {
  return `/api/progress`;
};

export const getProgress = async (
  options?: RequestInit,
): Promise<ProgressData> => {
  return customFetch<ProgressData>(getGetProgressUrl(), {
    ...options,
    method: "GET",
  });
};

export const getGetProgressQueryKey = () => {
  return [`/api/progress`] as const;
};

export const getGetProgressQueryOptions = <
  TData = Awaited<ReturnType<typeof getProgress>>,
  TError = ErrorType<unknown>,
>(options?: {
  query?: UseQueryOptions<
    Awaited<ReturnType<typeof getProgress>>,
    TError,
    TData
  >;
  request?: SecondParameter<typeof customFetch>;
}) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey = queryOptions?.queryKey ?? getGetProgressQueryKey();

  const queryFn: QueryFunction<Awaited<ReturnType<typeof getProgress>>> = ({
    signal,
  }) => getProgress({ signal, ...requestOptions });

  return { queryKey, queryFn, ...queryOptions } as UseQueryOptions<
    Awaited<ReturnType<typeof getProgress>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type GetProgressQueryResult = NonNullable<
  Awaited<ReturnType<typeof getProgress>>
>;
export type GetProgressQueryError = ErrorType<unknown>;

/**
 * @summary Get user progress data
 */

export function useGetProgress<
  TData = Awaited<ReturnType<typeof getProgress>>,
  TError = ErrorType<unknown>,
>(options?: {
  query?: UseQueryOptions<
    Awaited<ReturnType<typeof getProgress>>,
    TError,
    TData
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseQueryResult<TData, TError> & { queryKey: QueryKey } {
  const queryOptions = getGetProgressQueryOptions(options);

  const query = useQuery(queryOptions) as UseQueryResult<TData, TError> & {
    queryKey: QueryKey;
  };

  return { ...query, queryKey: queryOptions.queryKey };
}

/**
 * @summary Update current weight
 */
export const getUpdateProgressUrl = () => {
  return `/api/progress`;
};

export const updateProgress = async (
  updateProgressInput: UpdateProgressInput,
  options?: RequestInit,
): Promise<ProgressData> => {
  return customFetch<ProgressData>(getUpdateProgressUrl(), {
    ...options,
    method: "POST",
    headers: { "Content-Type": "application/json", ...options?.headers },
    body: JSON.stringify(updateProgressInput),
  });
};

export const getUpdateProgressMutationOptions = <
  TError = ErrorType<unknown>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof updateProgress>>,
    TError,
    { data: BodyType<UpdateProgressInput> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationOptions<
  Awaited<ReturnType<typeof updateProgress>>,
  TError,
  { data: BodyType<UpdateProgressInput> },
  TContext
> => {
  const mutationKey = ["updateProgress"];
  const { mutation: mutationOptions, request: requestOptions } = options
    ? options.mutation &&
      "mutationKey" in options.mutation &&
      options.mutation.mutationKey
      ? options
      : { ...options, mutation: { ...options.mutation, mutationKey } }
    : { mutation: { mutationKey }, request: undefined };

  const mutationFn: MutationFunction<
    Awaited<ReturnType<typeof updateProgress>>,
    { data: BodyType<UpdateProgressInput> }
  > = (props) => {
    const { data } = props ?? {};

    return updateProgress(data, requestOptions);
  };

  return { mutationFn, ...mutationOptions };
};

export type UpdateProgressMutationResult = NonNullable<
  Awaited<ReturnType<typeof updateProgress>>
>;
export type UpdateProgressMutationBody = BodyType<UpdateProgressInput>;
export type UpdateProgressMutationError = ErrorType<unknown>;

/**
 * @summary Update current weight
 */
export const useUpdateProgress = <
  TError = ErrorType<unknown>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof updateProgress>>,
    TError,
    { data: BodyType<UpdateProgressInput> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationResult<
  Awaited<ReturnType<typeof updateProgress>>,
  TError,
  { data: BodyType<UpdateProgressInput> },
  TContext
> => {
  return useMutation(getUpdateProgressMutationOptions(options));
};
